      "coverage": "adequate",
      "gaps": [
        "No log entry for retry attempts (attempt number, backoff delay, next retry scheduled_at)",
        "No log entry for renewals that were scheduled but never picked up (silent drops)",
        "No correlation ID / trace ID for following a renewal across scheduler → processor → billing API → retry"
      ]
    },
    "metrics": {
      "coverage": "gaps",
      "gaps": [
        "CRITICAL: No renewal_scheduling_lag_seconds metric (scheduled_time vs processed_time). This is the only way to measure the 1-hour SLO.",
