      },
      {
        "scenario": "Retry mechanism fails — failed renewals are never retried",
        "handling": "unhandled",
        "recommendation": "No retry tracking metrics. If the retry consumer crashes or the retry queue is misconfigured, failed renewals silently die. Add retry_pending_total gauge, retry_executed_total counter, and alert if any failed renewal has not been retried within 24 hours."
      },
      {
        "scenario": "Poison message — one malformed renewal blocks the processor",
        "handling": "unhandled",
        "recommendation": "No mention of dead-letter queue or poison message handling. A single bad message could stall the entire pipeline. Add DLQ with alerting on DLQ depth."
      },
      {
        "scenario": "Clock skew or timezone bug causes batch of renewals to be scheduled incorrectly",
        "handling": "unhandled",
        "recommendation": "The scheduling_lag metric (when added) would catch this as a sudden spike. Ensure scheduled_time and processed_time use UTC and log timezone explicitly."
